//data-processor-helpers.js
/**************** Data Processor Helper Functions  **************/
import { BAR_CHARTNAME, BULLET_CHARTNAME, DIAL_CHARTNAME, BOXPLOT_CHARTNAME, BARRANGE_CHARTNAME } from '../chartname-constants';
import { DataProcessor } from '../data-processor';
import { defined, isArray, pick, getPropVal, arrayIncludes, d3_values, invokeFunction } from '../../utils/zcutils';
import { NUMERIC_DATATYPE } from '../datatype-constants';
import { charttype, charttypenames } from '../main-zc-init';
import { mathAbs } from '../zc-constants';
import { d3_ascending } from '../d3-constants';
import { effects } from '../../effects/zceffects';

DataProcessor.helpers = {
    /**
     *
     * @param dataset
     * @param type
     * @param index
     * @return {Function}
     */

    isCatNull: function(dataset, type, index) {
        var noNullFormat = dataset.hasNullFormatter && !dataset.hasNullFormatter[type + (defined(index) ? index : '')];
        return function(cat) {
            return !defined(cat) && noNullFormat;
        };
    },

    /**
     *
     * @param data
     * @return {boolean}
     */

    is3D: function(data) {
        return isArray(data) && isArray(data[0]) && isArray(data[0][0]);
    },

    getParsedYAxisOrder: function(yaxiscolumnorder) {
        return isArray(yaxiscolumnorder) ? yaxiscolumnorder[0] : yaxiscolumnorder || 0;
    },

    /**
     *
     * @param type
     * @param chartTypeBy
     * @param index
     * @param data
     * @return {{name: *, value: *}}
     */
    getChartType: function(type, chartTypeBy, index, data) {
        if (type == null && index == null) {
            return;
        }

        var seriesdata = data && data.seriesdata.chartdata,
            chartName,
            chartValue,
            defaultType = 'bar';
        if (defined(index)) {
            type = pick((seriesdata[index] || seriesdata[0]).type, data.seriesdata.type, defaultType);
        }
        if (isNaN(+type)) {
            chartName = type.toLowerCase();
            chartValue = charttype[chartName];
        } else {
            chartValue = +type || 9;
            chartName = charttypenames.get(chartValue);
        }
        return chartTypeBy === 'string'
            ? chartName
            : chartTypeBy === NUMERIC_DATATYPE
            ? chartValue
            : {
                  name: chartName,
                  value: chartValue
              };
    },

    /**
     *
     * @param data
     * @param chartTypeBy
     */

    getAllChartTypes: function(data, chartTypeBy) {
        var helpers = this;
        var globalChartType = data.seriesdata && data.seriesdata.type;

        return pick(getPropVal(data, 'seriesdata.chartdata'), []).map(function(a) {
            var temp = helpers.getChartType(pick(a.type, globalChartType, 'bar'), pick(chartTypeBy, NUMERIC_DATATYPE));
            if (!chartTypeBy && chartTypeBy === 'object') {
                return {};
            }
            return temp;
        });
    },

    /**
     *
     * @param data
     * @param chartTypeBy
     */

    getAllChartTypesFromSeriesdata: function(userdata, processedSeriesdata, chartTypeBy) {
        var helpers = this;
        var globalChartType = userdata.seriesdata && userdata.seriesdata.type;

        return pick(processedSeriesdata, []).map(function(a) {
            var temp = helpers.getChartType(pick(a.type, globalChartType), pick(chartTypeBy, NUMERIC_DATATYPE));
            if (!chartTypeBy && chartTypeBy === 'object') {
                return {};
            }
            return temp;
        });
    },

    /**
     *
     * @param array
     * @param rangeX
     * @param accessorX
     * @param rangeY
     * @param accessorY
     * @return {*}
     */
    filterDataToViewPort: function(array, rangeX, accessorX, rangeY, accessorY) {
        let both = isArray(rangeX) && isArray(rangeY),
            counter = 0;

        return array.filter(function(d) {
            var valX = accessorX && accessorX(d);
            var valY = accessorY && accessorY(d);
            var show;

            if (both) {
                show = valX !== null && valY !== null && valX >= rangeX[0] && valX <= rangeX[1] && valY >= rangeY[0] && valY <= rangeY[1];
            } else {
                show = valX !== null && valX >= rangeX[0] && valX <= rangeX[1];
            }

            if (show) {
                d._filter = false;
                d.counter = counter++;
            } else {
                d._filter = true;
            }
            return show;
        });
    },

    /**
     *
     * @param point
     * @param property
     * @param seriesIndex
     * @param subSeriesIndex
     * @param chart
     * @param chartType
     * @param xScale
     * @param yScale
     * @return {*}
     */
    getDataPosition(point, property, seriesIndex = 0, subSeriesIndex = 0, chart, chartType, xScale, yScale) {
        let renderer = chart.renderer[seriesIndex],
            rendererConf = chart.rendererConf[seriesIndex], // TODO: PIVOT
            yAxisOrder = rendererConf.yaxiscolumnorder(),
            rotated = chart.axes.rotated,
            stacked = rendererConf.stacked(),
            position = null;

        chartType = pick(chartType, chart.chartTypes[seriesIndex].name);
        xScale = pick(xScale, rendererConf.xscale());
        yScale = pick(yScale, rendererConf.yscale());

        if (chartType === 'bar') {
            position = chart.dataObject.getTransRectValue(property, point, subSeriesIndex, 0, renderer.commonOption);
        } else if (chartType === 'bubblepie') {
            // #ZC2073
            let referencePoint = point[seriesIndex];
            position = chart.dataObject.getXYvalue(rotated, stacked, xScale, yScale, yAxisOrder, referencePoint, property);
        } else {
            position = chart.dataObject.getXYvalue(rotated, stacked, xScale, yScale, yAxisOrder, point, property);
        }

        if (isNaN(position)) {
            position = null;
        }
        return position;
    },

    filterPointsInViewport: function(chart, points, chartType, axisType, seriesIndex = 0, subSeriesIndex = 0) {
        // #ZC2193
        if (chart.isGeoMap) {
            // TODO GEO CHARTS
            return points;
        }

        // #ZC2219
        let needPositionCorrection = arrayIncludes(['line', 'area', 'bar', 'arearange', 'canvasscatter'], chartType),
            plotArea = chart.plotarea,
            rangeX = [0, plotArea.width],
            rangeY = [0, plotArea.height],
            rotated = chart.axes.rotated,
            reversed = chart.axes.x.reversed,
            getPosition = DataProcessor.helpers.getDataPosition;

        if ((axisType === 'x' || axisType === 'xy') && isArray(chart.scrollView)) {
            // if(!(chart.racing && chart.racing.scrollView)){
                rangeX = chart.scrollView.map(chart.axes.x.baseScale).sort(d3_ascending);
            // }
        }
        if(chart.racing && chart.racing.scrollView){
            //we need to use the saved value since scroll.getSelection will give the current position of scroll, 
            //which will also animated, and the position got from it will not be the final position.
            rangeX = invokeFunction(chart.racing.scrollView, true);
        }
        //avoid the correction for racing, not needed.
        if (needPositionCorrection && (points.length > 1 || chartType === 'bar') && !chart.racing) {
            if (chartType === 'bar') {
                if (rotated) {
                    rangeX = rangeY;
                }
                rangeX = [rangeX[0] - chart.barscale2.bandwidth(), rangeX[1]];
            } else {
                let correctionX,
                    correctionY,
                    p0_x = getPosition(points[0], 'x', seriesIndex, subSeriesIndex, chart, chartType),
                    p1_x = getPosition(points[1], 'x', seriesIndex, subSeriesIndex, chart, chartType),
                    p0_y = getPosition(points[0], 'y', seriesIndex, subSeriesIndex, chart, chartType),
                    p1_y = getPosition(points[1], 'y', seriesIndex, subSeriesIndex, chart, chartType);
                if (reversed) {
                    correctionX = p0_x - p1_x;
                    correctionY = p0_y - p1_y;
                } else {
                    correctionX = p1_x - p0_x;
                    correctionY = p1_y - p0_y;
                }

                if (rotated) {
                    [correctionX, correctionY] = [correctionY, correctionX].map(mathAbs);
                    [rangeX, rangeY] = [rangeY, rangeX];
                }

                rangeX = [rangeX[0] - correctionX, rangeX[rangeX.length-1] + correctionX];
                rangeY = [rangeY[0] - correctionY, rangeY[rangeY.length-1] + correctionY];
            }
        } else {
            if (rotated) {
                [rangeX, rangeY] = [rangeY, rangeX];
            }
        }

        let accessorX = d => getPosition(d, rotated ? 'y' : 'x', seriesIndex, subSeriesIndex, chart, chartType),
            accessorY = d => getPosition(d, rotated ? 'x' : 'y', seriesIndex, subSeriesIndex, chart, chartType);

        if (axisType === 'xy') {
            return DataProcessor.helpers.filterDataToViewPort(points, rangeX, accessorX, rangeY, accessorY);
        } else if (axisType === 'x') {
            return DataProcessor.helpers.filterDataToViewPort(points, rangeX, accessorX);
        } else if (axisType === 'y') {
            return DataProcessor.helpers.filterDataToViewPort(points, rangeY, accessorY);
        }
    },

    groupByDataIndices: function(metadata, chart) {
        /*
         * returns an array of groupby dataindices
         */
        var dataSplicer = chart.dataSplicer,
            metadata_axes = dataSplicer.getEncode(),
            metadata_columns = dataSplicer.getColumns();

        var groupbyCol = metadata_axes.groupby || [];
        return groupbyCol.map(function(d) {
            return metadata_columns[d].dataindex;
        });
    },

    /**
     * @param  {Object} processor [description]
     * @param  {Number} index     [description]
     * @return {Boolean}           [description]
     */
    hasLevelMarkerData: function(processor, index) {
        var LEVELMARKER_LIST = [BAR_CHARTNAME, BULLET_CHARTNAME, DIAL_CHARTNAME, BOXPLOT_CHARTNAME, BARRANGE_CHARTNAME],
            seriesIndices = processor.getEncode('y', index).seriesIndices,
            allChartTypes = processor.allChartTypes,
            check = seriesIndex => arrayIncludes(LEVELMARKER_LIST, charttypenames.get(allChartTypes[seriesIndex]));

        return seriesIndices.some(check);
    },

    /*
     * @return {boolean}
     */
    hasMarkerCorrection: function(processor) {
        return false;
        // var markerSize = getMarkerSize(processor.chartObj);
        // return markerSize.left > 0 || markerSize.right > 0 || markerSize.top > 0 || markerSize.bottom > 0;
    },

    /**
     *
     * @param chartId
     * @param seriesIndex
     * @param subSeriesIndex
     * @param itemIndex
     * @return {string}
     */
    generatePointKey: function(chartId, gridId, seriesIndex, subSeriesIndex, itemIndex) {
        return `${chartId}_${gridId}_${seriesIndex}_${subSeriesIndex}_${itemIndex}`;
    },

    getSeriesdata: function(chart, paneid, seriesIndex) {
        if (defined(seriesIndex)) {
            if (chart.dataObject.pivot) {
                var layers = chart.dataObject.hierarchical.pivotLayout.getRootNodeList('layer'),
                    panes = layers.panes;
                return panes[paneid].data[seriesIndex].node;
            } else {
                return chart.seriesdata[seriesIndex];
            }
        }
    },

    getDynamicData: function(data, chart) {
        let data_dynamic = d3_values(data);
        var co = data_dynamic.count;
        for (var i = 0; i <= co; i++) {
            data_dynamic.splice(i, 0, [null, null]);
        }
        return data_dynamic;
    }
};
